var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"으윽, 머리 가죽이 벗겨지는 줄 알았어……","JPN":"ううっ、頭皮がはがれるかと思ったよ……","ENG":"Ngh... I thought my scalp was gonna tear off...","TWN":"呃呃，頭皮都要被扯下來了……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"학부장님 뒤만 정신없이 따라오긴 했는데…… 여긴 대체 어디일까요?","JPN":"学部長様の後ろを無我夢中に追ってはきましたけど……ここはいったいどこなのでしょう？","ENG":"Where are we? We just followed wherever the dean was going, and–","TWN":"雖然糊裡糊塗地跟著學院院長過來了……這裡究竟是哪裡？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"방공호 같군. 대정화 전쟁 시절에 지었다가 방치된 모양이야.","JPN":"防空壕のようだな。大浄化戦争の頃に建設されてから、放置されていたようだ。","ENG":"It looks like a panic room. It was built during the Grand Purification War but was abandoned.","TWN":"好像是防空洞。似乎是淨化之戰時期建的，現在閒置了。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_B","text":{"KOREA":"됐습니다. 여기라면 기관의 전략 위성도 한동안 추격에 애를 먹을 겁니다.","JPN":"教授、ここなら機関の戦略衛星もしばらく追撃に苦労するはずです。","ENG":"This should do. We should be able to hide from the Institution's satellites in here.","TWN":"可以了。這裡的話，機關的戰略衛星搜尋起來也得花一段時間。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그렇군. 전용기는 준비되었나?","JPN":"そうか。専用機の準備はできているか？","ENG":"Good. And what about the plane?","TWN":"是啊。專機準備好了嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_B","text":{"KOREA":"죄송합니다, 교수님. 비행장에서도 소요가 발생했다고 연락 받았습니다.","JPN":"申し訳ございません、教授。飛行場でも騒動が発生したとの連絡がありました。","ENG":"My apologies, Professor. I was informed that there was a problem at the airport as well.","TWN":"對不起，教授。剛剛接到通知，說是機場也發生了騷動。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그래. 기관장이 손을 썼나 보군…….","JPN":"うむ。機関長が手を回したようだな……","ENG":"I see. I guess the chief of the Institution stepped in...","TWN":"嗯，看來是機關長出手了……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"버넷 경의 손자만 보냈다는 건 이목을 분산시키려는 계획임을 알아차렸기 때문이겠지. 영리한 아가씨야.","JPN":"バーネット卿の孫だけを向かわせたということは、注意を分散させる計画だと気付いたからだろう。賢いお嬢さんだ。","ENG":"By the looks of only sending out Sir Burnett's grandson, she probably figured out that this was all a distraction. Smart girl.","TWN":"只派出了伯內特卿的孫子，應該是看破我們的計畫，想分散他們的注意力吧。真是個聰明的小姐。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"추가로 배편을 수배해 주게. 브로커가 얼마를 부르든 상관없어.","JPN":"追加で船便を手配してくれ。ブローカーがいくらを要求しようと構わない。","ENG":"Find us a boat. I'll pay whatever the broker asks for.","TWN":"另外再去找一搜船。不管偷渡掮客要多少錢，都無所謂。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_B","text":{"KOREA":"예. 바로 알아 보겠습니다.","JPN":"はい。すぐに調べてみます。","ENG":"Yes, sir. I'll look for one right away.","TWN":"是的，我馬上去找。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"이런 일에 휘말리게 해서 미안합니다, 맥크레디 양.","JPN":"こんなことに巻き込んでしまってすみません、マクレディーさん。","ENG":"I'm sorry you got tangled in this mess, Ms. MacCready.","TWN":"對不起，讓你捲進這種事，麥克蕾蒂。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_B","text":{"KOREA":"감히 교수님의 따귀를 때려! 무슨 짓이냐!","JPN":"教授のお顔を！　何をするんだ！","ENG":"Huh?! How dare you slap the Professor?!","TWN":"你竟敢打教授耳光！你在幹什麼！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"가만히 있게. 내 제자이기 이전에 부학회장님이실세.","JPN":"静かに。私の教え子である前に副学会長なのだ。","ENG":"Halt. She is the Vice President before being my student.","TWN":"住手，她雖然是我的學生，但更是副學會長。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"……따귀를 맞은 건 오랜만이군요. 맥크레디 양도 어머니처럼 손맛이 매운 편입니다.","JPN":"……頬を叩かれたのは久しぶりですね。マクレディーさんの平手打ちはお母さんに似ていて痛いです。","ENG":"…It's been a while since someone slapped me. Your slaps feel just like your mother's.","TWN":"……好久沒挨耳光了。麥克蕾蒂下手也很重呢，跟你的母親一樣。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"대체 뭐죠……?","JPN":"いったい何なのですか……？","ENG":"What is all this...?","TWN":"究竟是怎麼回事……？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"왜 당신이 고고학부장이에요? 합중국을 뒤엎는다는 건 또 무슨 소리고요?","JPN":"どうしてあなたが考古学部長なのですか？　合衆国をひっくり返すというのは、どういうことですの？","ENG":"Why are you the Dean of Archeology? And what is that about overtaking the States?","TWN":"你為什麼是考古學院院長？推翻合眾國又是什麼意思？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"순서가 잘못되었습니다. 고고학부장인 제가 교수로 부임한 것이죠.","JPN":"順番が間違っています。考古学部長である私が、教授として赴任したわけです。","ENG":"The order is wrong. As Dean of Archeology, I was hired as a professor.","TWN":"順序錯了。應該說是身為考古學院院長的我赴任當了教授。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"왜 당신들은 내 옆에서 얼쩡거리지 못해서 안달이에요? 학회가 그렇게 중요해?!","JPN":"あなたたち、どれだけ私と関わりたいんですの？　そんなに学会が重要なの！？","ENG":"What is it with you all that you cannot help but bother me?! What is so important about the Society?!","TWN":"你們為什麼要一直在我身邊糾纏不休？學會就那麼重要嗎？！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"중요하지는 않지만 필요합니다.","JPN":"重要ではありませんが、必要です。","ENG":"It is not about importance, but necessity.","TWN":"雖然不重要，但卻是必要的。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"아직까지는 제 호기심을 풀 수 있는 유일한 수단이기 때문이죠.","JPN":"現時点では私の好奇心を満足させてくれる唯一の手段ですから。","ENG":"It is the only way I can satisfy my curiosity.","TWN":"因為到目前為止，這是我能解開好奇心的唯一方法。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"호기심이라니요……?","JPN":"好奇心……？","ENG":"Your curiosity...?","TWN":"好奇心……？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"밤하늘의 별이 몇 개인지 궁금했던 적 있습니까? 그들이 목소리를 낼 수 있을까요?","JPN":"夜空の星が何個あるか、疑問に思ったことはありますか？　星は答えられるのでしょうか？","ENG":"Have you ever wondered how many stars are up in the night sky? Or if they have voices that we cannot hear?","TWN":"你好奇過夜空中有多少顆星星嗎？它們能發出聲音嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"강물의 유속이 얼마나 빠른지 아십니까? 숨을 쉬지 않으면 정말 죽어야 하는 겁니까?","JPN":"川の水の流れがどれほど速いか知っていますか？　呼吸をしないと本当に死んでしまうのでしょうか？","ENG":"Or do you know how fast the current of a river is? Do we really die if we don't breathe?","TWN":"你知道河水的流速有多快嗎？不呼吸真的就會死嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"맥크레디 양, 의문을 품지 않는다는 것은 살아 있는 매 순간 자신에게 죄를 짓는 것입니다.","JPN":"マクレディーさん、疑問を抱かないということは、人生のあらゆる瞬間において、自分自身への罪を犯しているのと同じことなのです。","ENG":"Ms. MacCready, not having doubts means that you are sinning every second of your life.","TWN":"麥克蕾蒂，心無疑問，對自己活著的每個瞬間來說都是犯罪。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그것 때문에…… 그런 것 때문에 온갖 범죄에 협력한다는 말인가요?","JPN":"そのために……そんなことのためにあらゆる犯罪に協力しているのですか？","ENG":"Is that why... Is that why you are collaborating with criminals?","TWN":"因為這樣……就因為這樣，你才和各種犯罪同流合污嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"글쎄요. 적어도 이렇게 매사 방해 받는 삶은 저도 원치 않았습니다.","JPN":"どうでしょう。少なくとも、こうやってことごとく邪魔される人生を望んではいませんでしたね。","ENG":"Well. At the very least, I didn't want to live a life where I would be chained to conventional norms.","TWN":"怎麼說呢，至少我想要的不是這種每件事都會受阻的生活。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"시작은 단순한 의문이었죠. 법의 테두리는 얼마나 견고한가?","JPN":"最初は単なる疑問でした。法の枠はどれほど強固なのか。","ENG":"It all started with a simple question: \\"How sturdy are the boundaries of law?\\"","TWN":"一開始就是單純的疑問。法律的界限有多牢靠呢？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"지식은 우리가 사는 현실에 존재합니다. 책 속에 담긴 것은 주장이죠.","JPN":"知識は私たちが住んでいる現実に存在します。本の中に載っているのは主張です。","ENG":"Knowledge exists in the same reality as us. What books contain are claims.","TWN":"知識存在於我們生活的現實中。書中包含的僅僅只是主張。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"애석하게도 근거의 타당성을 책 속의 문장만으로 납득하기엔, 저는 무척이나 옹졸한 인물이었습니다.","JPN":"残念ながら根拠の妥当性を本の中の文章だけで納得するには、私の心が狭すぎたのです。","ENG":"Unfortunately, I was a very petty person who only understood the validity of the evidence from the book's sentences.","TWN":"可惜的是，對於僅憑書中的語句來理解依據的合理性，我是個非常狹隘的人。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저는 당신을 존경했습니다. 학식으로나, 인격적으로나.","JPN":"私はあなたを尊敬していましたわ。学識の面でも、人格的な面でも。","ENG":"I respected you. As a person and as an academic.","TWN":"我曾經很尊敬你，不管是學識還是人格。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당신도 그 사실을 알고 있었겠죠. 저는 그런 감정을 숨기는 데 능숙하지 않으니까요.","JPN":"あなたもその事実をご存じだったはずです。私はそういった感情を隠すのが苦手でしたから。","ENG":"You must have noticed, as I am not good at hiding my feelings.","TWN":"你應該也知道吧。因為我不擅長隱藏這種感情。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그런데 왜…… 왜 정체를 밝히지 않았어요?","JPN":"なのにどうして……どうして正体を明かさなかったのですか？","ENG":"But why... Why did you not tell me who you were?","TWN":"可是為什麼……你為什麼不說出真實身份？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L39_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아무것도 모르고 멍청하게 뛰어다니는 제 모습이 우스꽝스러워서?","JPN":"何も知らず、ばかみたいに走り回る私の姿がおもしろおかしくて？","ENG":"Did you find it entertaining to see me cluelessly running about?","TWN":"看著什麼都不知道，只知道傻乎乎地跑來跑去的我很可笑吧？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L40_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"제가 일찍부터 밝혔다면, 맥크레디 양이 학회를 대하는 태도도 지금 같지는 않았을 겁니다.","JPN":"私が早くから正体を明かしていたら、学会に対するマクレディーさんの態度も今と違っていたでしょう。","ENG":"If I had revealed who I really was, Ms. MacCready, your attitude towards the Society wouldn't be the same as it is now.","TWN":"如果我早點說出來，麥克蕾蒂對待學會的態度，也不會像現在這樣。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"That is...","TWN":"我……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"학회장님의 서신을 받은 날부터 줄곧 기대해 왔습니다.","JPN":"学会長の手紙をもらった日から、ずっと楽しみにしてきました。","ENG":"I've been eagerly awaiting it since the day I received a letter from the President.","TWN":"從收到學會長的書信那天開始，我就一直很期待。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"맥크레디 양이 학회에 변화를 불러올 것이라고 말입니다.","JPN":"マクレディーさんが学会に変化をもたらしてくれるとね。","ENG":"That you, Ms. MacCready, will bring changes to the Society.","TWN":"麥克蕾蒂會給學會帶來什麼變化。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그리고 그 기대는…… 지금도 그대로입니다.","JPN":"そしてその期待は……今も同じです。","ENG":"And that expectation is... still the same.","TWN":"還有，那份期待……現在也沒變。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그래요. 학회야 아무래도 상관없고, 그 변화가 파국일지 어떨지만 궁금할 뿐이겠죠.","JPN":"そうですわね。学会はさておき、その変化が破局であるかどうかが気になるだけでしょう。","ENG":"Very well. But you are more interested with whether the change will cause destruction or not than with what happens to the Society.","TWN":"是嗎。其實學會怎樣都無所謂吧，你只是好奇那種變化究竟會失敗還是別的結果。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"역시 이해가 빠르군요. 정확합니다.","JPN":"やはり飲み込みが早い。そのとおりです。","ENG":"A keen observation. Yes, that is correct.","TWN":"你理解得果然很快，沒錯。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};